code = """import re
import json
import pandas as pd

# The result from query_db is a list containing a single string.
raw_output_string = locals()['var_function-call-2063014923475659793']['results'][0]

# Find the first occurrence of '[' and the last occurrence of ']' to extract the JSON array string.
start_index = raw_output_string.find('[')
end_index = raw_output_string.rfind(']')

business_data = []
if start_index != -1 and end_index != -1 and start_index < end_index:
    json_array_string = raw_output_string[start_index : end_index + 1]
    try:
        business_data = json.loads(json_array_string)
    except json.JSONDecodeError as e:
        # In case of a JSON decoding error, print it and proceed with empty data
        print(f"JSON decoding error: {e}")
        print(f"Problematic string (first 500 chars): {json_array_string[:500]}...")

df_business = pd.DataFrame(business_data)

def extract_state(description):
    # Regex to find a two-letter uppercase state code preceded and followed by a comma and space
    match = re.search(r',\s*([A-Z]{2})\s*,', description)
    if match:
        return match.group(1)
    return None

df_business['state'] = df_business['description'].apply(extract_state)
df_business['review_count'] = pd.to_numeric(df_business['review_count'], errors='coerce')

# Drop rows where state could not be extracted or review_count is NaN
df_business.dropna(subset=['state', 'review_count'], inplace=True)

state_review_counts = df_business.groupby('state')['review_count'].sum().reset_index()

highest_review_state = None
total_reviews_in_state = 0
business_refs_in_state = []

if not state_review_counts.empty:
    highest_review_state_info = state_review_counts.loc[state_review_counts['review_count'].idxmax()]
    highest_review_state = highest_review_state_info['state']
    total_reviews_in_state = highest_review_state_info['review_count']

    business_ids_in_state = df_business[df_business['state'] == highest_review_state]['business_id'].tolist()

    # Convert business_id to business_ref format for joining with the review table
    business_refs_in_state = [bid.replace("businessid_", "businessref_") for bid in business_ids_in_state]

print('__RESULT__:')
print(json.dumps({
    'highest_review_state': highest_review_state,
    'total_reviews_in_state': total_reviews_in_state,
    'business_refs_in_state': business_refs_in_state
}))"""

